<template>

  <div class="sign-in">
    <div class="form__card outer-pad">
      <header class="form__card-header">
        <div class="h1">Inicia Sesión</div>
      </header>
      <p class="form__card-description">Digita tu usuario y contraseña para acceder a tu cuenta.</p>
      <form @submit.prevent="checkPasswordandEmail()" action="submit" class="form__card-fields">
        <fieldset>
          <label for="" class="label--input">Correo electrónico</label>
          <input v-model="userEmail"
                 :class="{'form__card-fields--failed' : !isEmailValid}"
                 type="text">
          <div class="form__password-wrapper">
            <label for="" class="label--input">Contraseña</label>
            <input v-model="userPassword"
                  ref="inputPass"
                  class="form__card-field"
                  :type="!passShown ? 'password' : 'text'"
                  :class="{'form__card-fields--failed' : !isPasswordValid}">
            <div class="icons__wrapper">
              <deleteText @click="this.userPassword = ''" class="icon__delete-text" v-show="userPassword !== ''"> </deleteText>
              <show-password v-if="!passShown" ref="showPass" @click="this.togglePass(true)"></show-password>
              <hide-password v-if="passShown" ref="hidePass" @click="this.togglePass(false)"></hide-password>
            </div>
          </div>
        </fieldset>
        <button class="button button--wide button--large">Inicia Sesión</button>
      </form>
      <footer class="form__card-footer">
        <p class="paragraph--dark">¿No tienes cuenta?<br><router-link :to='{name: "registro"}'>Registrate aquí.</router-link></p>
      </footer>
    </div>
    <alert typeOfAlert="loginError" v-if="!this.isEmailValid || !this.isPasswordValid"></alert>
    <router-view v-slot="{ Component }">
      <transition name="fade" appear mode="out-in">
        <component :is="Component" />
      </transition>
    </router-view>
  </div>

</template>

<script>
// @ is an alias to /src
import Alert from '../Alert'
import hidePassword from '../../icons/textfields/hidePassword'
import showPassword from '../../icons/textfields/showPassword'
import deleteText from '../../icons/textfields/deleteText'

export default {
  name: 'SignIn',
  data () {
    return {
      userPassword: '',
      userEmail: '',
      isPasswordValid: Boolean,
      isEmailValid: Boolean,
      passShown: false
    }
  },
  methods: {
    checkPasswordandEmail (e) {
      const userPassword = 'holamundo'
      const userEmail = 'hola@mundo.com'

      this.isPasswordValid = userPassword === this.userPassword
      this.isEmailValid = userEmail === this.userEmail
      this.isEmailValid && this.$router.push('code-verification')
    },
    togglePass (show) {
      this.passShown = show
    }
  },
  components: {
    hidePassword,
    showPassword,
    deleteText,
    Alert
  }
}
</script>
