<template>
  <div class="sign-up">
    <div class="form__card outer-pad" v-if="!this.$route.path.includes('completar-registro')">
      <header class="form__card-header">
        <div class="h1">Registrate</div>
        <router-link :to='{name: "ingresar"}'>Iniciar sesión</router-link>
      </header>
      <p class="form__card-description">Completa los datos para crear tu cuenta y acceder a los beneficios</p>
      <form @submit.prevent="goToCompleteDataRoute" action="submit" class="form__card-fields">
        <fieldset>
          <label for="" class="label--input">Correo electrónico</label>
          <input class="form__card-field" v-model="userEmail" ref="emailField" type="text">
          <div class="pass-input__wrapper">
            <label for="" class="label--input">Contraseña</label>
            <input class="form__card-field" ref="passField" @input="checkPassword" v-model="userPassword" :type="!passShown ? 'password' : 'text'">
            <show-password v-if="!passShown" ref="showPass" @click="this.togglePass(true)"></show-password>
            <hide-password v-if="passShown" ref="hidePass" @click="this.togglePass(false)"></hide-password>
          </div>
        </fieldset>
        <label class="checkbox__container label--checkbox">Debe contener como mínimo una mayúscula, un número y un símbolo.
          <input type="checkbox" :checked="isPasswordValid">
          <span class="checkmark"></span>
        </label>
        <button class="button button--wide button--large">Registrarme</button>
      </form>
      <footer class="form__card-footer">
        <p class="paragraph--dark">Al registrarme, estoy aceptando los <br><a href="">Términos y condiciones.</a></p>
      </footer>
    </div>
    <alert typeOfAlert="emailError" v-if="!this.isEmailValid"></alert>
    <alert typeOfAlert="passwordError" v-if="!this.isPasswordValid && this.userPassword"></alert>
    <datepicker v-if="1+1===3"></datepicker>
    <router-view v-slot="{ Component }">
      <transition name="fade" appear mode="out-in">
        <component :is="Component" />
      </transition>
    </router-view>
  </div>
</template>

<script>
import hidePassword from '../../icons/textfields/hidePassword'
import showPassword from '../../icons/textfields/showPassword'
import Datepicker from '../dashboard/prestamos/Datepicker.vue'
import Alert from '../Alert'

export default {
  name: 'SignUp',
  data () {
    return {
      userPassword: '',
      hasUpperCase: false,
      hasLowerCase: false,
      hasSymbol: false,
      isPasswordValid: false,
      isEmailValid: Boolean,
      userEmail: '',
      passShown: false
    }
  },
  methods: {
    checkPassword () {
      const symbols = /[ !@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/
      const upperCase = /[A-Z]/
      const lowerCase = /[a-z]/
      const isLength = this.userPassword.length > 8
      this.hasSymbol = symbols.test(this.userPassword)
      this.hasUpperCase = upperCase.test(this.userPassword)
      this.hasLowerCase = lowerCase.test(this.userPassword)
      this.isPasswordValid = this.hasSymbol && this.hasUpperCase && isLength
    },
    checkEmail () {
      const validEmailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9-]+(?:\.[a-zA-Z0-9-]+)*$/
      this.isEmailValid = validEmailRegex.test(this.userEmail)
      !this.isEmailValid && this.$refs.emailField.classList.add('form__card-fields--failed')
    },
    goToCompleteDataRoute () {
      this.checkEmail()
      this.userPassword && this.$refs.passField.classList.toggle('form__card-fields--failed', !this.isPasswordValid)
      if (this.isPasswordValid && this.isEmailValid) {
        this.$router.push({ name: 'completar-registro' })
      }
    },
    togglePass (show) {
      this.passShown = show
    }
  },
  components: {
    showPassword,
    hidePassword,
    Datepicker,
    Alert
  }
}
</script>
