<template>
  <transition name="fade" mode="out-in" appear>
    <div class="recover-account">
      <div class="form__card outer-pad">
        <header class="form__card-header">
          <account-icon></account-icon>
          <router-link class="custom-link" :to="{name: 'ingresar'}"><button class="button close">X</button></router-link>
        </header>
        <div class="h1">Recupera tu cuenta</div>
        <p class="form__card-description">Introduce tu dirección de correo electrónico y te enviaremos un enlace para restablecer la contraseña.</p>
        <form @submit.prevent="checkEmail()" action="submit" class="form__card-fields">
          <fieldset>
            <label for="" class="label--input">Correo electrónico</label>
            <input :class="{'form__card-fields--failed' : alertType !== ''}"
                    type="text"
                    v-model="userEmail">
          </fieldset>
          <button class="button button--wide button--large">Enviar</button>
        </form>
        <footer class="form__card-footer">
        </footer>
      </div>
      <alert :typeOfAlert="alertType" v-if="alertType !== ''"></alert>
    </div>
  </transition>
</template>

<script>
// @ is an alias to /src
import accountIcon from '../../icons/signin/accountIcon'
import Alert from '../Alert'

export default {
  name: 'RecoverAccount',
  data () {
    return {
      userEmail: '',
      apiEmail: 'hola@mundo.com',
      isEmailValid: false,
      showAlert: false,
      alertType: ''
    }
  },
  methods: {
    checkEmail () {
      const validEmailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9-]+(?:\.[a-zA-Z0-9-]+)*$/
      this.isEmailValid = validEmailRegex.test(this.userEmail)
      this.alertType = this.isEmailValid ? 'mailSent' : 'emailError'
    }
  },
  components: {
    accountIcon,
    Alert
  },
  mounted () {
  }
}
</script>
