<template>
  <transition name="fade" mode="out-in" appear>
    <div class="recover-account">
      <div class="form__card outer-pad">
        <header class="form__card-header">
          <new-pass-icon></new-pass-icon>
          <button class="button close">X</button>
        </header>
        <div class="h1">Crea una nueva contraseña</div>
        <p class="form__card-description">Ingresa tu nueva contraseña para iniciar sesión.</p>
        <form @submit.prevent="checkPassword()" action="submit" class="form__card-fields">
          <fieldset>
            <div class="form__password-wrapper">
              <label for="" class="label--input">Contraseña</label>
              <input v-model="userPassword"
                    type="password"
                    :class="{'form__card-fields--failed' : !isPasswordValid}">
              <div class="icons__wrapper">
                <deleteText class="icon__delete-text" v-show="userPassword !== ''"></deleteText>
                <hidePassword class="icon__hide-password"> </hidePassword>
                <showPassword class="icon__show-password"> </showPassword>
              </div>
            </div>
          </fieldset>
          <button class="button button--wide button--large">Enviar</button>
        </form>
        <footer class="form__card-footer">
        </footer>
      </div>
    </div>
  </transition>
</template>

<script>
// @ is an alias to /src
import newPassIcon from '../../icons/signin/newPassIcon'
import hidePassword from '../../icons/textfields/hidePassword'
import showPassword from '../../icons/textfields/showPassword'
import deleteText from '../../icons/textfields/deleteText'

export default {
  name: 'RecoverAccount',
  data () {
    return {
      userPassword: '',
      hasUpperCase: false,
      hasLowerCase: false,
      hasSymbol: false,
      isPasswordValid: false
    }
  },
  methods: {
    checkPassword () {
      const symbols = /[ !@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/
      const upperCase = /[A-Z]/
      const lowerCase = /[a-z]/
      const isLength = this.userPassword.length > 8

      this.hasSymbol = symbols.test(this.userPassword)
      this.hasUpperCase = upperCase.test(this.userPassword)
      this.hasLowerCase = lowerCase.test(this.userPassword)
      this.hasSymbol && this.hasUpperCase && isLength ? this.isPasswordValid = true : this.isPasswordValid = false

      console.log(this.isPasswordValid)
    }
  },
  components: {
    newPassIcon,
    hidePassword,
    showPassword,
    deleteText
  },
  mounted () {
  }
}
</script>
