<template>
  <div class="dashboard-view__wrapper">
    <dashboard-header buttonText="Agregar referencia" routeLink="agregar-referencia" title="Referencias personales" previousTitle="Mi cuenta"></dashboard-header>
    <references-empty-state v-if="isEmptyComputed"></references-empty-state>
    <transition name="fade" appear mode="out-in">
      <div class="account-references__view-wrapper" v-if="this.$route.name === 'referencias-personales'">
        <ul class="account__work-experience work-experience__wrapper">
          <li class="component-spacer" v-for="(reference, index) in references" :key="reference.id">
            <personal-reference-card @toggleDialogFromChild="toggleDialog(index)" :title="reference.name" :index="index"></personal-reference-card>
          </li>
        </ul>
        <transition name="fade" appear mode="out-in">
          <div class="account__dialog-wrapper" v-if="showDialog">
            <div class="account__delete-dialog dashboard-card">
              <header class="account__delete-header">
                <h2 class="account__delete-title">¿Está seguro de borrar esta experiencia laboral?</h2>
                <button class="button close" @click="toggleDialog(-1)">X</button>
              </header>
              <section class="account__delete-content">
                <p class="account__delete-text">Todos los datos de esta experiencia laboral serán borrados y no pueden ser recuperados.</p>
              </section>
              <footer class="account__delete-actions">
                <button class="button account__delete-button account__delete-button--bordered">Cancelar</button>
                <button class="button account__delete-button" @click="removeReference">Borrar</button>
              </footer>
            </div>
          </div>
        </transition>
      </div>
    </transition>
    <transition name="fade" appear mode="out-in">
      <add-account-reference v-if="this.$route.name === 'agregar-referencia'"></add-account-reference>
    </transition>
  </div>
</template>

<script>
import referencesEmptyState from '../../components/account/referencesEmptyState'
import personalReferenceCard from '../../components/account/personalReferenceCard'
import AddAccountReference from './AddAccountReference'
import DashboardHeader from '../../components/dashboard/DashboardHeader'

export default {
  name: 'AccountPersonalReferences',
  components: {
    referencesEmptyState,
    personalReferenceCard,
    AddAccountReference,
    DashboardHeader
  },
  data () {
    return {
      isEmpty: false,
      selectedIndex: null,
      showDialog: false,
      personalReferences: [
        {
          id: 0,
          name: 'Gonzalo Fernandez Osorio'
        },
        {
          name: 'Hello One and Two'
        },
        {
          name: 'Hellow Three and Four'
        }
      ]
    }
  },
  methods: {
    toggleDialog (index) {
      this.showDialog = !this.showDialog
      this.selectedIndex = index
    },
    removeReference () {
      this.personalReferences.splice(this.selectedIndex, 1)
      this.showDialog = false
    },
    updateEmptyState () {
      this.$emit('updateView')
    }
  },
  computed: {
    references () {
      return this.personalReferences
    },
    isEmptyComputed () {
      return this.personalReferences.length < 1
    }
  },
  watch: {
    'personalReferences.length' () {
      console.log('hello')
    }
  }
}
</script>
