<template>
  <div class="take-photo">
    <div class="take-photo__camera">
      <p class="paragraph--dark take-photo__header" v-if="cameraType === 'back'">Foto del lado posterior de tu documento</p>
      <p class="paragraph--dark take-photo__header" v-else>Foto del lado frontal de tu documento</p>
      <div class="camera-button">
        <a type="button" class="button--small is-rounded" v-if="!isPhotoTaken" :class="{ 'is-primary' : !isCameraOpen, 'is-danger' : isCameraOpen}" @click="toggleCamera">
          <span v-if="!isCameraOpen">Abrir cámara</span>
          <span v-else>Cerrar cámara</span>
        </a>
      </div>
      <button @click="closeComponent();" class="button close">X</button>
      <div class="camera-box">
        <div v-show="!isPhotoTaken" class="video--container">
          <video class="camera-video" ref="camera" :width="450" :height="337.5" autoplay playsinline ></video>
        </div>
        <canvas class="canvas-photo" v-show="isPhotoTaken" id="photoTaken" ref="canvas" :width="420" :height="280"></canvas>
      </div>
      <p v-if="!isPhotoTaken" class="paragraph--light">Asegúrate de que haya buena iluminación y ajusta la página con la imagen de tu documento hasta que encaje dentro del recuadro blanco.
        Toca el icono de la cámara cuando lo tengas todo listo.</p>
      <div v-else class="photo-footer">
        <p class="paragraph--dark photo-footer__header">Has escaneado tu documento ¿está bien?</p>
        <p class="paragraph--light photo-footer__desc">Debe mostrar claramente la página con tu foto. <br>
          *La imagen no debe salir desenfocada, cortada, ni con reflejos.
        </p>
        <div class="photo-footer__button-container">
          <button @click="toggleCamera" class="button button--gray photo-footer__button">Volver a intentarlo</button>
          <button @click="$parent.$parent.$parent.closeCamera" class="button photo-footer__button">Confirmar</button>
        </div>
      </div>
      <div v-if="!isPhotoTaken" class="camera-shoot">
        <camera-icon type="button" :style="{opacity: isCameraOpen ? 1 : 0.1}" class="button--small" @click="takePhoto"></camera-icon>
      </div>
    </div>
  </div>
</template>

<script>
import cameraIcon from '../../icons/signup/cameraIcon'

export default {
  name: 'TakePhoto',
  data () {
    return {
      isCameraOpen: false,
      isPhotoTaken: false
    }
  },
  props: {
    cameraType: {
      type: String,
      required: true
    }
  },
  methods: {
    createCameraElement () {
      let cameraConstrain = null
      window.navigator.userAgentData?.mobile ? cameraConstrain = { exact: 'environment' } : cameraConstrain = null
      const constraints = (window.constraints = {
        audio: false,
        video: {
          facingMode: cameraConstrain
        }
      })

      navigator.mediaDevices
        .getUserMedia(constraints)
        .then(stream => {
          console.log(constraints)
          this.$refs.camera.srcObject = stream
        })
        .catch(error => {
          alert(error, "May the browser didn't support or there is some errors.")
        })
    },
    stopCameraStream () {
      console.log(this.$refs.camera.srcObject)
      const tracks = this.$refs.camera.srcObject.getTracks()

      tracks.forEach(track => {
        track.stop()
      })
    },
    toggleCamera () {
      if (this.isCameraOpen) {
        this.stopCameraStream()
        this.isPhotoTaken = false
      } else {
        this.createCameraElement()
      }
      this.isCameraOpen = !this.isCameraOpen
    },
    takePhoto () {
      const context = this.$refs.canvas.getContext('2d')
      const photoFromVideo = this.$refs.camera
      const sx = 100
      const sy = 70
      const sWidth = 650
      const sHeight = 500
      context.drawImage(photoFromVideo, sx, sy, sWidth, sHeight, 0, 0, 600, 400)
      this.savePhoto()
      this.isPhotoTaken = !this.isPhotoTaken
      this.isCameraOpen = !this.isCameraOpen
    },
    savePhoto () {
      if (this.$props.cameraType === 'front') {
        this.$parent.$parent.$parent.idData.frontPicSrc = this.photoSrc
      } else if (this.$props.cameraType === 'back') {
        this.$parent.$parent.$parent.idData.backPicSrc = this.photoSrc
      }
    },
    closeComponent () {
      this.$parent.$parent.$parent.takePhoto = false

      if (this.isCameraOpen) {
        this.stopCameraStream()
      }
    }
  },
  components: {
    cameraIcon
  },
  computed: {
    photoSrc () {
      return document.getElementById('photoTaken').toDataURL()
    }
  }
}

</script>
