<template>
  <div v-if="this.$parent.showDatepicker" class="datepicker">
      <div class="datepicker__card">
        <p class="paragraph--dark">Selecciona una fecha</p>
    <button @click="this.$parent.showDatepicker=false" class="button close">X</button>
    <calendar
      class="calendar"
      v-model="selectedDate"
      :inline="true"
      dateFormat="yy.mm.dd"
      :date-select="pickDate()">
    </calendar>
    </div>
  </div>
</template>

<script>
import Calendar from 'primevue/calendar'

export default {
  data () {
    return {
      selectedDate: null
    }
  },
  methods: {
    pickDate () {
      if (this.selectedDate) {
        const formattedDate = this.selectedDate.getDate() + '/' + (this.selectedDate.getMonth() + 1) + '/' + this.selectedDate.getFullYear()
        this.$parent.selectedDate = formattedDate
        this.$parent.showDatepicker = false
      }
    }
  },
  components: {
    Calendar
  }
}
</script>
